module sr_latch (
    input wire clk,
    input wire S,
    input wire R,
    output reg Q
);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (S && !R) 
            Q <= 1'b1; // Set
        else if (!S && R) 
            Q <= 1'b0; // Reset
        // If S=0 and R=0, Q remains unchanged
    end
endmodule
